import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [authCode, setAuthCode] = useState(null);
  const [idToken, setIdToken] = useState(null);
  const [userProfile, setUserProfile] = useState(null);

  const handleLogin = () => {
    // Redirect to authorization endpoint with client_id and redirect_uri
    window.location.href = `https://authorization-server.com/oauth/authorize?client_id=YOUR_CLIENT_ID&redirect_uri=${window.location.origin}/callback`;
  };

  const handleCallback = () => {
    // Extract authorization code from URL hash
    const authCode = window.location.hash.split('=')[1];

    // Exchange authorization code for tokens
    axios.post(`https://authorization-server.com/oauth/token`, {
      client_id: 'YOUR_CLIENT_ID',
      redirect_uri: `${window.location.origin}/callback`,
      grant_type: 'authorization_code',
      code: authCode,
    })
      .then(response => {
        const accessToken = response.data.access_token;
        const idToken = response.data.id_token;

        // Decode id_token to get user profile
        axios.post(`https://authorization-server.com/oauth/token`, {
          client_id: 'YOUR_CLIENT_ID',
          redirect_uri: `${window.location.origin}/callback`,
          grant_type: 'authorization_code',
          code: idToken,
        })
          .then(response => {
            const userProfile = response.data;
            setUserProfile(userProfile);
          });
      });
  };

  return (
    <div>
      <button onClick={handleLogin}>Log in</button>
      {authCode && <p>Authorization code: {authCode}</p>}
      {idToken && <p>ID token: {idToken}</p>}
      {userProfile && <p>User profile: {JSON.stringify(userProfile)}</p>}
    </div>
  );
}